function tradesData() {
  var quarters = ['Q1', 'Q2', 'Q3', 'Q4']
  var days = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri']
  var out = []
  for (var i = 0; i < 90; i++) {
    out.push({
      quarter: quarters[Math.floor(i / 23) % 4],
      day: days[i % 5],
      outcome: i % 3 === 0 ? 'Loss' : 'Gain',
    })
  }
  return out
}

// Register the shared records BEFORE the charts are constructed.
ApexCharts.crossfilter({ id: 'trades', records: tradesData() })

var options = {
  series: [],
  chart: {
    id: 'byDayQuarter',
    type: 'heatmap',
    height: 300,
    fontFamily: 'Helvetica, Arial, sans-serif',
    animations: { speed: 450 },
    link: {
      id: 'trades',
      dimension: function (r) {
        return [r.day, r.quarter]
      },
      reduce: 'count',
    },
  },
  title: { text: 'Trades by day x quarter', align: 'left' },
  dataLabels: { enabled: true },
  plotOptions: {
    heatmap: { radius: 3, enableShades: true, shadeIntensity: 0.6 },
  },
  colors: ['#6366f1'],
}

var chart = new ApexCharts(document.querySelector('#chart'), options)
chart.render()

var options1 = {
  series: [],
  chart: {
    id: 'byOutcome',
    type: 'donut',
    height: 250,
    fontFamily: 'Helvetica, Arial, sans-serif',
    animations: { speed: 450 },
    link: {
      id: 'trades',
      dimension: function (r) {
        return r.outcome
      },
      reduce: 'count',
      dimOpacity: 0.18,
    },
  },
  title: { text: 'Outcome', align: 'left' },
  legend: { position: 'bottom', fontSize: '12px' },
  plotOptions: { pie: { expandOnClick: false } },
  dataLabels: {
    enabled: true,
    formatter: function (v, o) {
      return o.w.config.series[o.seriesIndex]
    },
  },
  // Records are first-seen ordered, and the data emits 'Loss' first, so the
  // domain is [Loss, Gain]: red for Loss, green for Gain.
  colors: ['#ef4444', '#22c55e'],
}

var chart1 = new ApexCharts(document.querySelector('#chart2'), options1)
chart1.render()

var options2 = {
  series: [],
  chart: {
    id: 'byDay',
    type: 'bar',
    height: 250,
    fontFamily: 'Helvetica, Arial, sans-serif',
    animations: { speed: 450 },
    link: {
      id: 'trades',
      dimension: function (r) {
        return r.day
      },
      reduce: 'count',
      seriesName: 'Trades',
      dimOpacity: 0.18,
    },
  },
  title: { text: 'Day of week', align: 'left' },
  plotOptions: {
    bar: { columnWidth: '55%', borderRadius: 3, distributed: true },
  },
  legend: { show: false },
  dataLabels: { enabled: false },
  colors: ['#6366f1', '#0ea5e9', '#22c55e', '#f59e0b', '#a855f7'],
}

var chart2 = new ApexCharts(document.querySelector('#chart3'), options2)
chart2.render()

// charts[0] = heatmap (target), charts[1] = outcome donut, charts[2] = day bar.
// The wiring talks to the crossfilter engine (not the chart instances).
var cf = ApexCharts.getCrossfilter('trades')
var readout = document.getElementById('cf-readout')

if (cf) {
  cf.on('change', function (state) {
    var ids = Object.keys(state.filters)
    readout.textContent =
      state.filteredCount +
      ' / ' +
      state.total +
      ' trades   (active: ' +
      (ids.length ? ids.join(', ') : 'none') +
      ')'
  })
  var s = cf.state()
  readout.textContent =
    s.filteredCount + ' / ' + s.total + ' trades   (active: none)'
}

document.getElementById('cf-reset').addEventListener('click', function () {
  if (cf) cf.reset()
})

.cf-wrap {
  max-width: 700px;
  margin: 12px auto;
  font-family: Helvetica, Arial, sans-serif;
}
.cf-bar {
  display: flex;
  gap: 12px;
  align-items: center;
  flex-wrap: wrap;
  margin: 4px 6px 12px;
}
.cf-bar button {
  padding: 6px 13px;
  cursor: pointer;
  border: 1px solid #6366f1;
  color: #4338ca;
  background: #fff;
  border-radius: 6px;
  font-size: 13px;
  font-weight: 600;
}
.cf-bar .readout {
  font-family: monospace;
  font-size: 13px;
  color: #445;
}
.cf-card {
  border: 1px solid #eef;
  border-radius: 8px;
  padding: 6px;
  margin-bottom: 8px;
}
.cf-row {
  display: grid;
  /* Outcome donut + day bar sit side by side, stacking when the tile narrows. */
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 8px;
}
.cf-note {
  background: #eef2ff;
  border-left: 3px solid #6366f1;
  padding: 11px 15px;
  font-size: 13px;
  color: #234;
  border-radius: 2px;
  line-height: 1.6;
  margin: 12px 6px;
}
.cf-note code {
  background: #dfe3ff;
  padding: 1px 5px;
  border-radius: 3px;
}
